import React from 'react';
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { screen } from '@testing-library/react';
import { render, createMockFetch } from './setup';

describe('DynamicTable Component', () => {
  let originalFetch: typeof globalThis.fetch;

  beforeEach(() => {
    originalFetch = globalThis.fetch;
  });

  afterEach(() => {
    globalThis.fetch = originalFetch;
    vi.clearAllMocks();
  });

  it('renders loading skeleton when isLoading is true', async () => {
    const { DynamicTable } = await import('../src/components/tables/dynamic-table');

    globalThis.fetch = createMockFetch({
      '/api/sys/fields': { data: [] },
    });

    const { container } = render(
      <DynamicTable
        tableName="bus_test"
        data={[]}
        isLoading={true}
        totalCount={0}
        onView={vi.fn()}
        onEdit={vi.fn()}
        onDelete={vi.fn()}
      />
    );

    expect(container).toBeTruthy();
    expect(container.querySelector('.skeleton')).toBeTruthy();
  });

  it('renders rows when data is provided', async () => {
    const { DynamicTable } = await import('../src/components/tables/dynamic-table');

    globalThis.fetch = createMockFetch({
      '/api/sys/fields': { data: [] },
    });

    const sampleData = [
      { id: 'row-1', name: 'Test Item 1' },
      { id: 'row-2', name: 'Test Item 2' },
    ];

    const { container } = render(
      <DynamicTable
        tableName="bus_test"
        data={sampleData}
        isLoading={false}
        totalCount={2}
        onView={vi.fn()}
        onEdit={vi.fn()}
        onDelete={vi.fn()}
      />
    );

    expect(container).toBeTruthy();
    expect(container.querySelector('table')).toBeTruthy();
  });

  it('shows empty state when data array is empty and not loading', async () => {
    const { DynamicTable } = await import('../src/components/tables/dynamic-table');

    globalThis.fetch = createMockFetch({
      '/api/sys/fields': { data: [] },
    });

    const { container } = render(
      <DynamicTable
        tableName="bus_test"
        data={[]}
        isLoading={false}
        totalCount={0}
      />
    );

    expect(container).toBeTruthy();
    expect(container.querySelector('.empty-state')).toBeTruthy();
  });

  it('shows footer with record count when totalCount is provided', async () => {
    const { DynamicTable } = await import('../src/components/tables/dynamic-table');

    const sampleData = [{ id: '1', name: 'Item' }];

    const { container } = render(
      <DynamicTable
        tableName="bus_test"
        data={sampleData}
        isLoading={false}
        totalCount={10}
      />
    );

    expect(container.querySelector('.table-footer')).toBeTruthy();
  });
});

describe('API Mock Utilities', () => {
  it('createMockFetch returns 200 for known paths', async () => {
    const mockFetch = createMockFetch({
      '/api/bus/test_table': { data: [], meta: { total: 0 } },
    });

    const response = await mockFetch('/api/bus/test_table');
    expect(response.ok).toBe(true);
    expect(response.status).toBe(200);
  });

  it('createMockFetch returns 404 for unknown paths', async () => {
    const mockFetch = createMockFetch({});
    const response = await mockFetch('/api/unknown');
    expect(response.status).toBe(404);
  });

  it('createMockFetch returns correct response body', async () => {
    const testData = { data: [{ id: '1', name: 'Test' }] };
    const mockFetch = createMockFetch({
      '/api/test': testData,
    });

    const response = await mockFetch('/api/test');
    const body = await response.json();
    expect(body).toEqual(testData);
  });
});
